import fs from "node:fs";
import path from "node:path";
import { parseQuestionBank } from "./lib/question-parser.mjs";

const root = path.resolve(import.meta.dirname, "..");
const sourcePath = path.join(root, "question-bank-v2.md");
const outputPath = path.join(root, "src/data/questions/generated.ts");
const markdown = fs.readFileSync(sourcePath, "utf8");
const questionBanks = parseQuestionBank(markdown);

const output = `// This file is generated by scripts/generate-question-data.mjs.
// Do not edit it by hand. Edit question-bank-v2.md and regenerate.

import type { Level, Question } from "../../domain/assessment/types";

export const questionBanks: Record<Level, Question[]> = ${JSON.stringify(
  questionBanks,
  null,
  2,
)};
`;

fs.mkdirSync(path.dirname(outputPath), { recursive: true });

if (process.argv.includes("--check")) {
  const current = fs.existsSync(outputPath)
    ? fs.readFileSync(outputPath, "utf8")
    : "";
  if (current !== output) {
    console.error(
      `${path.relative(root, outputPath)} is stale; run npm run questions:generate`,
    );
    process.exit(1);
  }
  console.log(`${path.relative(root, outputPath)} is current`);
} else {
  fs.writeFileSync(outputPath, output);
  console.log(
    `generated ${path.relative(root, outputPath)} (${Object.values(questionBanks).flat().length} questions)`,
  );
}
